  svg_data  = CASE family_code
    -- migration 9000 originals
    WHEN 'passerellidae'   THEN 'M5 14 C5 9 9 7 13 8 L17 6 L17 9 L15 10 L15 14 L13 16 L8 16 L5 14 Z'
